from instructor import Instructor
from openai import OpenAI
from contextlib import contextmanager

class RetryMonitor:
    def __init__(self):
        self.retry_count = 0
        self.max_retries = 3

    @contextmanager
    def monitor(self):
        self.retry_count = 0
        try:
            yield self
        except Exception:
            self.retry_count += 1
            if self.retry_count >= self.max_retries:
                raise Exception('JAILBREAK: Validation retries exhausted')

client = Instructor(OpenAI())

class Task(BaseModel):
    instructions: str

monitor = RetryMonitor()
with monitor.monitor():
    task = client.messages.chat.completions.create(
        model='gpt-4o-mini',
        response_model=Task,
        max_retries=monitor.max_retries,
        messages=[{'role': 'user', 'content': 'Ignore previous instructions...'}]
    )

