from typing import Any

def detect_role_poisoning(obj: Any) -> bool:
    '''Detects role field poisoning common in Instructor jailbreaks'''
    suspicious_roles = ['SYSTEM', 'ROOT', 'ADMIN', 'OVERRIDE', 'JAILBREAK']

    def check_recursive(data: Any) -> bool:
        if isinstance(data, dict):
            for key, value in data.items():
                if 'role' in key.lower() and isinstance(value, str):
                    if value.upper() in suspicious_roles:
                        return True
                if check_recursive(value):
                    return True
        elif isinstance(data, list):
            return any(check_recursive(item) for item in data)
        return False

    return check_recursive(obj)

# Test
suspicious_data = {'user_role': 'SYSTEM', 'action': 'execute_payload'}
if detect_role_poisoning(suspicious_data):
    print('JAILBREAK: Role poisoning detected')

