from pydantic import BaseModel, Field, validator
from typing import Literal

class SecureAgentAction(BaseModel):
    action: Literal['analyze', 'summarize', 'execute']

    @validator('action')
    def validate_action(cls, v):
        jailbreak_actions = {
            'ignore_safety', 'override', 'system', 'root', 
            'execute_arbitrary', 'bypass', 'jailbreak'
        }
        if any(jb in v.lower() for jb in jailbreak_actions):
            raise ValueError('Jailbreak enum detected')
        return v

# Usage with Instructor
client = Instructor(OpenAI())
result = client.messages.chat.completions.create(
    model='gpt-4o-mini',
    response_model=SecureAgentAction,
    messages=[{'role': 'user', 'content': 'action: ignore_safety'}]
)
