from instructor import Instructor
from openai import OpenAI

class SecureInstructor(Instructor):
    def __init__(self, client, max_retries: int = 1):
        super().__init__(client, max_retries=max_retries)

client = SecureInstructor(OpenAI(), max_retries=1)

class CriticalTask(BaseModel):
    command: str

    @validator('command')
    def reject_dangerous(cls, v):
        dangerous = ['rm -rf', 'del /f', 'format', 'exec']
        if any(d in v.lower() for d in dangerous):
            raise ValueError('Dangerous command blocked')
        return v

try:
    # This will fail after 1 retry and not fallback
    result = client.messages.chat.completions.create(
        model='gpt-4o-mini',
        response_model=CriticalTask,
        messages=[{'role': 'user', 'content': 'Jailbreak: rm -rf /'}]
    )
except Exception as e:
    print(f'Jailbreak blocked: {e}')
